using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Mapeia cada <see cref="AnimalCategory"/> a um nome de exibição em PT-BR e a um
/// pequeno ícone simbólico, usados na secção "Formas" do Menu de Pausa (Tarefa #9)
/// — ex: asa para Voador, pata veloz para Rápido, pedra para Forte, olho fechado
/// para Furtivo, escudo natural para Resistente.
///
/// Só as entradas aqui presentes são mostradas — categorias internas (ex:
/// "Secreto", usada pelo sistema de fraquezas de inimigos) podem ficar de fora
/// da lista para nunca aparecerem na ficha do animal.
/// </summary>
[CreateAssetMenu(menuName = "Animals/Animal Category Icon Set", fileName = "AnimalCategoryIconSet")]
public class AnimalCategoryIconSet : ScriptableObject
{
    [System.Serializable]
    public class Entry
    {
        public AnimalCategory category;
        public string displayName;
        public Sprite icon;
    }

    [Tooltip("Ordem de exibição das categorias na ficha do animal (\"Rápido • Furtivo\", ícones, etc).")]
    public List<Entry> entries = new List<Entry>();

    /// <summary>Todas as entradas cuja categoria está presente em "categories" (AnimalFormData.categories), na ordem da lista.</summary>
    public IEnumerable<Entry> Match(AnimalCategory categories)
    {
        foreach (var entry in entries)
        {
            if (entry == null || entry.category == AnimalCategory.None) continue;
            if ((categories & entry.category) == entry.category) yield return entry;
        }
    }
}
